              step="0.01"
              value={val as number}
              onChange={(e) => handleSiteChange(site as any, parseFloat(e.target.value))}
               className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-teal-500 hover:accent-teal-400"
            />
          </div>
        ))}
      </section>
    </div>
  );
};

